// src/components/OfficerRow.js
import React from 'react';
import Swal from 'sweetalert2';
//import { deleteOfficer } from '../api';

const OfficerRow = ({ officer, onDelete }) => {
    const handleDelete = () => {
        Swal.fire({
            title: 'Are you sure?',
            text: "You won't be able to revert this!",
            icon: 'warning',
            showCancelButton: true,
            confirmButtonColor: '#3085d6',
            cancelButtonColor: '#d33',
            confirmButtonText: 'Yes, delete it!'
        }).then(async (result) => {
            if (result.isConfirmed) {
                //await deleteOfficer(officer.id);
                onDelete(officer.id);
            }
        });
    };

    return (
        <tr>
            <td>{officer.officer_number}</td>
            <td>{officer.name}</td>
            <td>{officer.wing}</td>
            <td>{officer.position}</td>
            <td>{officer.status}</td>
            <td>
                <button onClick={() => alert(`View ${officer.id}`)}>View</button>
                <button onClick={() => alert(`Update ${officer.id}`)}>Update</button>
                <button onClick={handleDelete}>Delete</button>
            </td>
        </tr>
    );
};

export default OfficerRow;
